#!/usr/bin/env dotnet
// friday13.cs â€” Friday the 13th explorer (proleptic Gregorian calendar)

// Find the earliest Friday the 13th starting from 0001-01-01
var date = new DateTime(1, 1, 13); // start on the 13th of January, year 1
while (date.DayOfWeek != DayOfWeek.Friday)
    date = date.AddMonths(1);

Console.WriteLine($"Earliest Friday the 13th: {date:yyyy-MM-dd} ({date:dddd, MMMM d, yyyy})");

// Count Friday the 13ths in one full 400-year cycle (the Gregorian calendar repeats every 400 years)
int count = 0;
var start = new DateTime(1, 1, 13);
var end = new DateTime(401, 1, 1);

for (var d = start; d < end; d = d.AddMonths(1))
{
    if (d.DayOfWeek == DayOfWeek.Friday)
        count++;
}

Console.WriteLine($"\nFriday the 13ths in a 400-year cycle (0001â€“0400): {count}");
Console.WriteLine($"Average per year: {count / 400.0:F4}");

// Bonus: which day-of-week lands on the 13th most often?
var dayCounts = new int[7];
for (var d = start; d < end; d = d.AddMonths(1))
    dayCounts[(int)d.DayOfWeek]++;

Console.WriteLine("\n13th-of-month distribution across 400 years:");
foreach (DayOfWeek dow in Enum.GetValues<DayOfWeek>())
    Console.WriteLine($"  {dow,-10} {dayCounts[(int)dow],4}");

var maxDay = Enum.GetValues<DayOfWeek>().MaxBy(d => dayCounts[(int)d]);
Console.WriteLine($"\nMost common day for the 13th: {maxDay} ({dayCounts[(int)maxDay]} times)");

